import './css/manageOfficers.css';
import React, { useEffect, useState } from 'react';

const ManageOfficers = () => {
  const [officers, setOfficers] = useState([]);
  const [error, setError] = useState(null);

  useEffect(() => {
    const fetchOfficers = async () => {
      try {
        const response = await fetch('http://localhost:8088/api/admin/get-all-users');
        if (!response.ok) {
          throw new Error('Failed to fetch officers');
        }
        const data = await response.json();
        console.log(data); // Log the response data
        
        // Check if data is an array before setting it
        if (Array.isArray(data)) {
          setOfficers(data);
        } else {
          throw new Error('Received data is not an array');
        }
      } catch (error) {
        console.error(error);
        setError('An error occurred while fetching officers.'); // Handle error
      }
    };
  
    fetchOfficers(); // Call the fetch function on component mount
  }, []);
  

  return (
    <div className="manage-officers">
      <h2>Manage Officers</h2>
      <table className="officer-table">
        <thead> 
          <tr>
            <th>ID</th>
            <th>Name</th>
            <th>Role</th>
            <th>Email</th>
            <th>Action</th>
          </tr>
        </thead>
        <tbody>
          {officers.map((officer, index) => (
            <tr key={index}>
              <td>{officer.id}</td>
              <td>{officer.name}</td>
              <td>{officer.role}</td>
              <td>{officer.email}</td>
              <td>
                <button>Edit</button>
                <button>Delete</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default ManageOfficers;
